INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00052', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列題辭，何者不適合用於祝賀新居落成？', '["竹苞松茂，肯堂肯構", "鳳卜宜昌，傳世之作", "鶯遷喬木，氣象維新", "華堂毓秀，雕樑畫棟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00053', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列句子「」中的用語，何者使用正確？', '["聽到老師榮升的好消息，「不肖」感到與有榮焉", "他犯錯被師長責備，卻表現出「不卑不亢」的精神", "那位挑戰金氏世界紀錄的人瑞，最後「得年」113歲", "他在「知命之年」便達到財富自由，比一般公務員提早退休"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00054', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列那一句話沒有冗詞贅字？', '["接下來醫生會幫您做一個檢查的動作，請先稍候", "關於這場比賽結果的部分，紅隊險勝了白隊三分", "為了養家，他無時無刻不在工作，最後累出病來", "今天必須回老家一趟，然後已經先跟公司請假了"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00055', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列成語應用，何者最為適當？', '["這種無枉無縱的態度，實在不太負責任", "這麼美的風景，瞬間就雲淡風輕地消逝", "祝你這趟環島旅行鵬程萬里，玩得盡興", "家人之間休戚與共，應該一起面對問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00056', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '俗話說：「人生沒有白走的路，每一步都算數。」下列選項，最符合文意的是：', '["做人留一線，日後好相見", "凡是走過的，必留下痕跡", "行到水窮處，坐看雲起時", "路遙知馬力，日久見人心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00057', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列文句沒有語病的是：', '["越瞭解自己的人，越能瞭解世界", "再過一會兒我們已經把工作完成", "要預測未來，首先要會展望過去", "這位女星曾經一度在麥當勞打工"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00058', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「我發現跑步與寫作的節奏非常類似。跑五公里其實跟寫五頁的報告很像，都是基礎能力。把五公里 跑好，重心清楚穩定地向前邁進，是關鍵的核心能力。沒能把五公里跑好，歪歪扭扭地跑到十幾公里 也只是傷了膝蓋而已。把一篇五頁的報告寫好也是基礎。」 根據上文，下列選項何者最符合文意？', '["行百里者，半於九十", "讀萬卷書，行萬里路", "千里之行，始於足下", "駑馬十駕，功在不舍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00059', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「我認為老房子改造咖啡館是非常適合的。因為老房子中總是有某種□□□□的氣息，咖啡香的瀰漫， 剛好可以去除那些老房子裡令人不愉快的氣味。」 根據上文，□□□□最為合適的詞語是：', '["環堵蕭然", "無聲無臭", "樸拙簡略", "古老陳腐"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00060', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「為考量競技運動選手培育的長遠規劃及運動科學發展，未來國家運動科學中心的業務，包括辦理國 家優秀運動選手所需之運動科學支援服務、健康管理及醫療照護，並進行國際賽事資訊之分析，亦將 衡酌該中心的量能，進行運動科技之研發、技術移轉及加值應用，提升產業競爭力。同時協助規劃及 培育運動科學人才，將運動科學成果推廣全民運用。」 根據上文，下列選項最符合國家運動科學中心的職責是：', '["培訓競技運動選手", "辦理國際運動賽事", "研擬運動科技新知和應用", "推廣民眾運動與休閒風氣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00061', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列選項「」中的成語，何者應用正確？', '["做事一定要有規劃，免得「相形見絀」", "考量時間「綽綽有餘」，我們就晚點出門", "平時不好好讀書，到頭來只能「代人捉刀」", "和他的作品比起來，我的就顯得「左右逢源」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
